/**
 * Helper function to normalize PGP armored strings
 * Ensures: blank line after header, Unix line endings (\n)
 */
export function normalizePGPArmor(armor: string): string {
  if (!armor) return armor;

  // Normalize line endings to \n
  let clean = armor.replace(/\r\n/g, '\n').replace(/\r/g, '\n').trim();

  // The keys already have proper blank lines after headers
  // No need to add extra ones
  return clean;
}

